import React, { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import FoodCard from "../components/foodcard.jsx";
import api from "../api";
import CartDrawer from "../components/CartDrawer.jsx";

const FALLBACK = "data:image/jpeg;base64,";
const onErr = (e) => { e.currentTarget.src = FALLBACK; e.currentTarget.onerror = null; };

// Local helpers to target public/images/chinese first
function slugifyName(str = "") {
  return String(str).toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");
}
function chineseLocalCandidates(name = "") {
  const slug = slugifyName(name);
  return [
    `/images/chinese/${slug}.jpg`,
    `/images/chinese/${slug}.jpeg`,
    `/images/chinese/${slug}.png`,
    `/images/chinese/${slug}.webp`,
  ];
}
function MultiSrcImage({ sources = [], alt = '', fallback, className = '', ...rest }) {
  const [idx, setIdx] = React.useState(0);
  const src = sources[idx] || fallback;
  return (
    <img
      src={src}
      alt={alt}
      onError={() => {
        if (idx + 1 < sources.length) setIdx(idx + 1);
        else if (fallback && src !== fallback) setIdx(sources.length);
      }}
      className={className}
      {...rest}
    />
  );
}

const ITEMS = [
  { name: "Fish in Hot Garlic Sauce", price: 170, img: "data:image/jpeg;base64," },
  { name: "Cantonese Roasted Pork", price: 160, img:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSk3Y0HcN45rXBEl2M2WXmGiDriLhDiseAuaA&s"},
   { name: "Dumplings", price: 140, img: "data:image/jpeg;base64," },
  { name: "Chilli Paneer", price: 190, img: "data:image/jpeg;base64," },
  { name: "Mapo Tofu", price: 150, img: "data:image/jpeg;base64," },
  { name: "Schezwan Noodles", price: 170, img: "data:image/jpeg;base64," },
  { name: "Kung Pao Veg", price: 200, img: "data:image/jpeg;base64," },
  { name: "Sichuan Hot Pot", price: 160, img: "data:image/jpeg;base64," },
  { name: "Hot and Sour Soup", price: 130, img: "data:image/jpeg;base64," },
  { name: "Schezwan Fried Rice", price: 170, img: "data:image/jpeg;base64," },
  { name: "Veg Chow Mein", price: 160, img: "data:image/jpeg;base64," },
  { name: "Tofu Stir Fry", price: 190, img: "data:image/jpeg;base64," }
];

export default function Chinese() {
  const [cart, setCart] = useState({ items: [] });
  const [openCart, setOpenCart] = useState(false);
  const [items, setItems] = useState([]);

  useEffect(() => {
    (async () => {
      try {
        const crt = await api.get('/cart');
        setCart(crt.data || { items: [] });
        const res = await api.get('/items?category=chinese');
        setItems(res.data || []);
      } catch {}
    })();
  }, []);

  async function handleAddToCart(itemId, qty = 1) {
    try {
      await api.post('/cart', { itemId, qty });
      const crt = await api.get('/cart');
      setCart(crt.data || { items: [] });
    } catch {}
  }

  async function handleRemoveFromCart(itemId) {
    try {
      await api.delete(`/cart/${itemId}`);
      const crt = await api.get('/cart');
      setCart(crt.data || { items: [] });
    } catch {}
  }

  async function handleToggleSave(itemId) {
    try {
      await api.post(`/saved/${itemId}`);
    } catch {}
  }

  async function handleEnsureAndSave(fb) {
    try {
      const created = await api.post('/items', {
        name: fb.name,
        price: fb.price ?? 0,
        image: fb.img,
        categorySlug: 'chinese'
      });
      const id = created?.data?._id;
      if (id) await handleToggleSave(id);
    } catch {}
  }

  async function handleEnsureAndAdd(fb) {
    try {
      const created = await api.post('/items', {
        name: fb.name,
        price: fb.price ?? 0,
        image: fb.img,
        categorySlug: 'chinese'
      });
      const id = created?.data?._id;
      if (id) await handleAddToCart(id, 1);
    } catch {}
  }

  const total = useMemo(() => {
    return (cart.items || []).reduce((sum, item) => {
      const price = item.itemId?.price ?? 0;
      const qty = item.qty ?? 0;
      return sum + price * qty;
    }, 0);
  }, [cart.items]);

  return (
    <div className="min-h-screen bg-blue-50">
      <div className="max-w-6xl mx-auto p-4 sm:p-6">
        <div className="grid grid-cols-3 items-center gap-6 mb-5">
          <div className="justify-self-start">
            <Link to="/home" className="inline-flex items-center gap-2 px-5 py-2.5 text-base font-medium border rounded-md bg-gray-100 text-gray-700 hover:bg-gray-200">← Back</Link>
          </div>
          <div className="justify-self-center w-full max-w-xl mx-2">
            <div className="border-2 border-orange-500 rounded-lg bg-white">
              <h1 className="text-3xl font-extrabold text-orange-600 text-center py-2">Chinese Varieties</h1>
            </div>
          </div>
          <div className="justify-self-end">
            <button
              onClick={() => setOpenCart(true)}
              className="flex items-center gap-2 px-4 py-2 bg-[#ffad33] text-white rounded-lg hover:bg-[#ffa31a] transition-colors border border-[#ffad33]"
            >
              Cart
              {(cart.items?.length ?? 0) > 0 && (
                <span className="ml-1 bg-red-500 text-white text-xs rounded-full h-5 w-5 flex items-center justify-center">
                  {cart.items.length}
                </span>
              )}
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {(Array.isArray(items) ? items : []).map((it, i) => (
            <div key={it._id || `api-${i}`} className="bg-white rounded-xl shadow-sm border border-[#ffad33] hover:shadow-md transition-shadow overflow-hidden">
              <div className="aspect-video rounded-t-xl overflow-hidden">
                <MultiSrcImage
                  sources={[...chineseLocalCandidates(it.name), ...(it.image ? [it.image] : [])]}
                  fallback={FALLBACK}
                  alt={it.name}
                  className="w-full h-full object-cover"
                  referrerPolicy="no-referrer"
                />
              </div>
              <div className="p-3">
                <div className="font-semibold text-gray-900">{it.name}</div>
                {it.price != null && <div className="text-sm text-gray-600">₹{it.price}</div>}
                <div className="mt-3 flex gap-2">
                  <button className="px-3 py-2 bg-[#ffad33] text-white rounded hover:bg-[#ffa31a]" onClick={() => handleAddToCart(it._id)}>Add to Cart</button>
                  <button className="px-3 py-2 border border-[#ffad33] text-[#ffad33] rounded hover:bg-[#ffad33]/10" onClick={() => handleToggleSave(it._id)}>Save</button>
                </div>
              </div>
            </div>
          ))}
          {(Array.isArray(items) && items.length > 0 ? ITEMS.slice(0, Math.max(0, 12 - items.length)) : ITEMS).map((it, i) => (
            <div key={`fb-${i}`} className="bg-white rounded-xl shadow-sm border border-[#ffad33] hover:shadow-md transition-shadow overflow-hidden">
              <div className="aspect-video rounded-t-xl overflow-hidden">
                <MultiSrcImage
                  sources={[...chineseLocalCandidates(it.name), ...(it.img ? [it.img] : [])]}
                  fallback={FALLBACK}
                  alt={it.name}
                  className="w-full h-full object-cover"
                  referrerPolicy="no-referrer"
                />
              </div>
              <div className="p-3">
                <div className="font-semibold text-gray-900">{it.name}</div>
                {it.price != null && <div className="text-sm text-gray-600">₹{it.price}</div>}
                <div className="mt-3 flex gap-2">
                  <button className="px-3 py-2 bg-[#ffad33] text-white rounded hover:bg-[#ffa31a]" onClick={() => handleEnsureAndAdd(it)}>Add to Cart</button>
                  <button className="px-3 py-2 border border-[#ffad33] text-[#ffad33] rounded hover:bg-[#ffad33]/10" onClick={() => handleEnsureAndSave(it)}>Save</button>
                </div>
              </div>
            </div>
          ))}
        </div>
        <CartDrawer open={openCart} onClose={() => setOpenCart(false)} items={cart.items || []} total={total} onRemove={handleRemoveFromCart} />
      </div>
    </div>
  );
}